import * as path from 'path';
import * as fs from 'fs';
import * as os from 'os';
import nock from 'nock';

describe('image downloader - relative path resolution', () => {
  it('should resolve relative dest path to absolute path', async () => {
    const { image } = require('../../../../../../../../../../../subject_repositories/image-downloader/index.js');

    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'img-test-'));
    const imageData = Buffer.from('fake image data');

    nock('http://example.com')
      .get('/image.jpg')
      .reply(200, imageData, { 'content-type': 'image/jpeg' });

    const result = await image({ url: 'http://example.com/image.jpg', dest: tmpDir, extractFilename: true });

    expect(path.isAbsolute(result.filename)).toBe(true);

    fs.rmSync(tmpDir, { recursive: true });
  });
});
